exercises.solution:
import hashlib

class XMSSHash:
    def __init__(self, n: int = 32):
        self.n = n

    def F(self, key: bytes, data: bytes, addr: bytes) -> bytes:
        prefix = bytes([0]) * self.n
        return hashlib.sha256(prefix + key + addr + data).digest()[:self.n]

    def H(self, key: bytes, left: bytes, right: bytes, addr: bytes) -> bytes:
        prefix = bytes([1]) * self.n
        return hashlib.sha256(prefix + key + addr + left + right).digest()[:self.n]

    def PRF(self, key: bytes, data: bytes) -> bytes:
        prefix = bytes([2]) * self.n
        return hashlib.sha256(prefix + key + data).digest()[:self.n]

import math

class XMSSSize:
    def __init__(self, n: int, w: int, h: int):
        self.n = n
        self.w = w
        self.h = h
        log_w = int(math.log2(w))
        self.l1 = math.ceil(8 * n / log_w)
        self.l2 = math.floor(math.log2(self.l1 * (w-1)) / log_w) + 1
        self.l = self.l1 + self.l2

    def signature_size(self) -> int:
        return 4 + self.n + self.l * self.n + self.h * self.n

    def public_key_size(self) -> int:
        return 2 * self.n

    def secret_key_size(self) -> int:
        return 4 + 4 * self.n
